def has_cycle_directed(n, adj):
    WHITE, GRAY, BLACK = 0, 1, 2
    color = [WHITE] * n

    def dfs(u):
        color[u] = GRAY
        for v in adj.get(u, []):
            if color[v] == GRAY:    # back-edge -> cycle
                return True
            if color[v] == WHITE and ___________:
                return True
        color[u] = BLACK
        return False

    return any(dfs(u) for u in range(n) if color[u] == WHITE)

exercise.test_code:
# DAG — no cycle
adj1 = {0:[1,2], 1:[3], 2:[3], 3:[]}
assert not has_cycle_directed(4, adj1)

# Cycle: 0->1->2->0
adj2 = {0:[1], 1:[2], 2:[0]}
assert has_cycle_directed(3, adj2)

# Self-loop
adj3 = {0:[0]}
assert has_cycle_directed(1, adj3)

# Disconnected, one component cyclic
adj4 = {0:[1], 1:[0], 2:[3], 3:[]}
assert has_cycle_directed(4, adj4)
print('PASS')
